769#QT|
770#YR|      const truncateResult = this.tryTruncateRecovery(
771#XW|        tokensBefore,
772#YJ|        contextLimit
773#NM|      );
774#HZ|      if (truncateResult) {
775#BJ|        if (truncateResult.success) {
