781#NB|            totalTokens: estimatedTokens,
782#JH|            updatedAt: new Date(),
783#HJ|          };
784#RQ|        }
785#XM|        return truncateResult;
786#QM|      }
787#VV|
788#HX|      const tokensAfter = this.getEstimatedTokens();
789#YS|      return {
790#PQ|        success: false,
791#XW|        tokensBefore,
792#BP|        tokensAfter,
793#HV|        error: `context overflow recovery exhausted all strategies (prune → compact → aggressive-compact → truncate). tokensBefore=${tokensBefore}, tokensAfter=${tokensAfter}, contextLimit=${contextLimit}`,
794#YK|      };
795#MW|    } finally {
